   767→    const experience = await pool.query(
   768→      'SELECT title FROM work_experience WHERE user_id = $1 ORDER BY start_date DESC LIMIT 3',
   769→      [req.user.id]
   770→    );
   771→
   772→    // Get active jobs
   773→    const jobs = await pool.query(`
   774→      SELECT j.*, u.company_name as posted_by_company
   775→      FROM jobs j
   776→      LEFT JOIN users u ON j.user_id = u.id
   777→      WHERE j.status = 'active'
   778→      ORDER BY j.created_at DESC
   779→      LIMIT $1
   780→    `, [limit]);
   781→
   782→    const candidateProfile = {
