async function loadSkillsGraph() {
  try {
    const data = await apiCall('/candidate/skills');
    if (!data || !data.success || !data.skills || data.skills.length === 0) {
      renderEmptySkillsGraph();
      return;
    }
    renderSkillsGraph(data.skills);
  } catch (err) {
    console.error('Failed to load skills:', err);
    renderEmptySkillsGraph();
  }
}

function renderEmptySkillsGraph() {
  document.getElementById('skills-radar').innerHTML = `
    <div class="empty-skills-graph">
      <div class="radar-placeholder">
        <svg viewBox="0 0 200 200" class="radar-svg-empty">
          <polygon points="100,20 180,70 155,160 45,160 20,70" fill="none" stroke="var(--border-color)" stroke-width="1" opacity="0.3"/>
          <polygon points="100,50 150,82 135,135 65,135 50,82" fill="none" stroke="var(--border-color)" stroke-width="1" opacity="0.2"/>
          <circle cx="100" cy="100" r="3" fill="var(--text-muted)"/>
        </svg>
      </div>
      <p>Add skills to see your competency graph</p>
      <a href="/candidate-profile.html#skills" class="btn btn-primary btn-sm">Add Skills</a>
    </div>
  `;
  document.getElementById('skills-legend').innerHTML = '';
}

function renderSkillsGraph(skills) {
  // Group skills by category and calculate average levels
  const categories = {};
  skills.forEach(s => {
    const cat = s.category || 'technical';
    if (!categories[cat]) {
      categories[cat] = { total: 0, count: 0, verified: 0, skills: [] };
    }
    categories[cat].total += s.level;
    categories[cat].count++;
    if (s.is_verified) categories[cat].verified++;
    categories[cat].skills.push(s);
  });

  // Calculate averages
  const categoryData = Object.entries(categories).map(([name, data]) => ({
    name,
    avg: Math.round((data.total / data.count) * 20), // Convert 1-5 to percentage
    count: data.count,
    verified: data.verified,
    skills: data.skills
  }));

  // Render radar chart
  renderRadarChart(categoryData);

  // Render legend with top skills
  renderSkillsLegend(categoryData);
}

function renderRadarChart(categoryData) {
  const container = document.getElementById('skills-radar');
  const numAxes = categoryData.length;

  if (numAxes < 3) {
    // Not enough categories for radar - show bar chart instead
    container.innerHTML = `
      <div class="skills-bars">
        ${categoryData.map(cat => {
          const label = formatCategoryName(cat.name);
          return `
            <div class="skill-bar-item">
              <div class="skill-bar-header">
                <span class="skill-bar-label">${label}</span>
                <span class="skill-bar-value">${cat.avg}%</span>
              </div>
              <div class="skill-bar-track">
                <div class="skill-bar-fill" style="width: ${cat.avg}%"></div>
              </div>
              <span class="skill-bar-count">${cat.count} skill${cat.count !== 1 ? 's' : ''} ${cat.verified > 0 ? `(${cat.verified} verified)` : ''}</span>
            </div>
          `;
        }).join('')}
      </div>
    `;
    return;
  }

  const cx = 100, cy = 100, radius = 70;
  const angleStep = (2 * Math.PI) / numAxes;

  // Calculate points for each level (20%, 40%, 60%, 80%, 100%)
  const levels = [20, 40, 60, 80, 100];
  const levelPolygons = levels.map(level => {
    const r = (level / 100) * radius;
    return categoryData.map((_, i) => {
      const angle = i * angleStep - Math.PI / 2;
      return `${cx + r * Math.cos(angle)},${cy + r * Math.sin(angle)}`;
    }).join(' ');
  });

  // Calculate data points
  const dataPoints = categoryData.map((cat, i) => {
    const r = (cat.avg / 100) * radius;
    const angle = i * angleStep - Math.PI / 2;
    return `${cx + r * Math.cos(angle)},${cy + r * Math.sin(angle)}`;
  }).join(' ');

  // Axis lines
  const axisLines = categoryData.map((_, i) => {
    const angle = i * angleStep - Math.PI / 2;
    return `<line x1="${cx}" y1="${cy}" x2="${cx + radius * Math.cos(angle)}" y2="${cy + radius * Math.sin(angle)}" stroke="var(--border-color)" stroke-width="1"/>`;
  }).join('');

  // Labels
  const labels = categoryData.map((cat, i) => {
    const angle = i * angleStep - Math.PI / 2;
    const labelRadius = radius + 25;
    const x = cx + labelRadius * Math.cos(angle);
    const y = cy + labelRadius * Math.sin(angle);
    const label = formatCategoryName(cat.name);
    return `<text x="${x}" y="${y}" text-anchor="middle" dominant-baseline="middle" class="radar-label">${label}</text>`;
  }).join('');

  container.innerHTML = `
    <svg viewBox="0 0 200 200" class="radar-svg">
      <!-- Grid levels -->
      ${levelPolygons.map((points, i) => `<polygon points="${points}" fill="none" stroke="var(--border-color)" stroke-width="1" opacity="${0.2 + i * 0.1}"/>`).join('')}
      <!-- Axis lines -->
      ${axisLines}
      <!-- Data polygon -->
      <polygon points="${dataPoints}" fill="url(#radarGradient)" stroke="var(--accent-primary)" stroke-width="2" fill-opacity="0.3"/>
      <!-- Data points -->
      ${categoryData.map((cat, i) => {
        const r = (cat.avg / 100) * radius;
        const angle = i * angleStep - Math.PI / 2;
        const x = cx + r * Math.cos(angle);
        const y = cy + r * Math.sin(angle);
        return `<circle cx="${x}" cy="${y}" r="4" fill="var(--accent-primary)" class="radar-point" data-category="${cat.name}" data-value="${cat.avg}"/>`;
      }).join('')}
      <!-- Labels -->
      ${labels}
      <defs>
        <linearGradient id="radarGradient" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" style="stop-color:#10b981"/>
          <stop offset="100%" style="stop-color:#06b6d4"/>
        </linearGradient>
      </defs>
    </svg>
  `;
}

function renderSkillsLegend(categoryData) {
  const container = document.getElementById('skills-legend');

  container.innerHTML = `
    <div class="legend-header">
      <h4>Top Skills by Category</h4>
    </div>
    ${categoryData.map(cat => {
      const topSkills = cat.skills
        .sort((a, b) => b.level - a.level)
        .slice(0, 4);
      return `
        <div class="legend-category">
          <div class="legend-cat-header">
            <span class="legend-cat-name">${formatCategoryName(cat.name)}</span>
            <span class="legend-cat-avg">${cat.avg}% avg</span>
          </div>
          <div class="legend-skills">
            ${topSkills.map(s => `
              <span class="legend-skill ${s.is_verified ? 'verified' : ''}">
                ${s.skill_name}
                ${s.is_verified ? '<span class="v-badge">✓</span>' : ''}
                <span class="s-level">${'●'.repeat(s.level)}${'○'.repeat(5-s.level)}</span>
              </span>
            `).join('')}
            ${cat.skills.length > 4 ? `<span class="more-count">+${cat.skills.length - 4} more</span>` : ''}
          </div>
        </div>
      `;
    }).join('')}
    <div class="legend-cta">
      <a href="/skill-assessments.html" class="btn btn-primary btn-sm btn-full">Verify Skills with Assessment</a>
    </div>
  `;
}

function formatCategoryName(cat) {
  const names = {
    'technical': 'Technical',
    'soft_skill': 'Soft Skills',
    'tool': 'Tools',
    'language': 'Languages',
    'framework': 'Frameworks',
    'database': 'Databases'
  };
  return names[cat] || cat.charAt(0).toUpperCase() + cat.slice(1);
}

